svg.script:
var activeColor = '#FF6B6B';
var eraseMode = false;
var opacity = 1.0;
var sliding = false;
var history = [];

document.querySelectorAll('.swatch')[0].classList.add('active');

function pick(c, el) {
  activeColor = c;
  eraseMode = false;
  document.getElementById('preview').setAttribute('fill', c);
  document.getElementById('eraserBtn').setAttribute('fill','#0f3460');
  document.getElementById('eraserBtn').setAttribute('stroke','#444');
  document.querySelectorAll('.swatch').forEach(function(s){s.classList.remove('active');});
  el.classList.add('active');
}

function toggleErase() {
  eraseMode = !eraseMode;
  var el = document.getElementById('eraserBtn');
  el.setAttribute('fill', eraseMode ? '#fff0f0' : '#0f3460');
  el.setAttribute('stroke', eraseMode ? '#e94560' : '#444');
}

function fillRegion(el) {
  history.push({ el:el, fill:el.getAttribute('fill'), op:el.getAttribute('fill-opacity') });
  if (eraseMode) {
    el.setAttribute('fill','none');
    el.setAttribute('fill-opacity','1');
  } else {
    el.setAttribute('fill', activeColor);
    el.setAttribute('fill-opacity', opacity);
  }
}

function undo() {
  if (!history.length) return;
  var last = history.pop();
  last.el.setAttribute('fill', last.fill || 'none');
  last.el.setAttribute('fill-opacity', last.op || '1');
}

function clearAll() {
  document.querySelectorAll('.region').forEach(function(r){
    r.setAttribute('fill','none');
    r.setAttribute('fill-opacity','1');
  });
  history = [];
}

function startSlide(evt) { sliding=true; slideMove(evt); }
function endSlide() { sliding=false; }
function slideMove(evt) {
  if (!sliding) return;
  var svg = evt.target.ownerSVGElement;
  var pt = svg.createSVGPoint();
  pt.x = evt.clientX; pt.y = evt.clientY;
  var sp = pt.matrixTransform(svg.getScreenCTM().inverse());
  var pct = Math.max(0, Math.min(1, (sp.x - 620) / 100));
  opacity = pct;
  document.getElementById('opBar').setAttribute('width', Math.round(pct*100));
  document.getElementById('opLabel').textContent = Math.round(pct*100) + '%';
}
